sections.code_example:
class Animal:
    def speak(self):
        print("...")

class Dog(Animal):
    def speak(self):       # overrides Animal.speak
        print("Woof!")

class Cat(Animal):
    def speak(self):       # overrides Animal.speak
        print("Meow!")

dog = Dog()
cat = Cat()
dog.speak()   # Woof!
cat.speak()   # Meow!

class Animal:
    def __init__(self, name):
        self.name = name

    def describe(self):
        print(f"I am {self.name}.")

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)     # run Animal's __init__
        self.breed = breed

    def describe(self):            # extend Animal's describe
        super().describe()         # run parent version first
        print(f"I am a {self.breed}.")

rex = Dog("Rex", "Labrador")
rex.describe()

class Dog:
    def speak(self): return "Woof!"

class Cat:
    def speak(self): return "Meow!"

class Duck:
    def speak(self): return "Quack!"

animals = [Dog(), Cat(), Duck()]
for animal in animals:
    print(animal.speak())  # same call, different result

